-- Seed 5 avances de obra for Peace Avenue project
INSERT INTO avances_obra (proyecto_id, titulo, fecha, descripcion, video_url, imagen_url, orden) VALUES
('f4068eea-6ed7-4a0a-a985-ff62345e378e', 'Inicio de Cimentación', '2026-03-01',
  '<p>Se iniciaron las obras de cimentación profunda con pilotes de concreto reforzado. El sistema de cimentación fue diseñado para soportar las cargas de la estructura de 15 niveles, garantizando estabilidad y durabilidad.</p><p>Se completó la excavación de los primeros 12 pilotes con una profundidad promedio de 18 metros, alcanzando el estrato rocoso. Los ensayos de integridad arrojaron resultados satisfactorios.</p>',
  'https://www.youtube.com/watch?v=dQw4w9WgXcQ',
  'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', 0),

('f4068eea-6ed7-4a0a-a985-ff62345e378e', 'Excavación Completa', '2026-02-15',
  '<p>Excavación de 4,500 m² finalizada con éxito. Se retiraron aproximadamente 12,000 m³ de tierra, preparando el terreno para la fase de cimentación.</p><p>El proceso incluyó el retiro de material orgánico, la conformación de taludes de seguridad y la instalación del sistema de drenaje perimetral para control de aguas subterráneas.</p>',
  NULL,
  'https://images.unsplash.com/photo-1541888946425-d81bb19240f5?w=800&q=80', 1),

('f4068eea-6ed7-4a0a-a985-ff62345e378e', 'Aprobación de Licencias', '2026-01-20',
  '<p>Todas las licencias de construcción han sido obtenidas y aprobadas por la autoridad municipal. El proyecto cumple con todos los requisitos urbanísticos, ambientales y de seguridad sísmica exigidos por la normativa vigente.</p><p>Se recibió la licencia de construcción número LC-2026-0847 que autoriza la ejecución de la obra en todas sus etapas.</p>',
  NULL,
  'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80', 2),

('f4068eea-6ed7-4a0a-a985-ff62345e378e', 'Ceremonia de Primera Piedra', '2025-12-10',
  '<p>Evento oficial de colocación de la primera piedra con la presencia de inversionistas, autoridades municipales y el equipo directivo. La ceremonia marcó el inicio formal del proyecto Peace Avenue.</p><p>Más de 120 asistentes participaron en el evento, donde se presentó la maqueta arquitectónica y los renders finales del proyecto.</p>',
  'https://www.youtube.com/watch?v=dQw4w9WgXcQ',
  'https://images.unsplash.com/photo-1531834685032-c34bf0d84c77?w=800&q=80', 3),

('f4068eea-6ed7-4a0a-a985-ff62345e378e', 'Presentación del Proyecto', '2025-11-15',
  '<p>Lanzamiento oficial de Peace Avenue ante inversionistas y público general. Se presentaron los diseños arquitectónicos definitivos, las tipologías disponibles y el cronograma de obra.</p><p>El evento de lanzamiento contó con una experiencia inmersiva de realidad virtual que permitió a los asistentes recorrer virtualmente los apartamentos modelo y las zonas comunes del proyecto.</p>',
  NULL,
  'https://images.unsplash.com/photo-1497366216548-37526070297c?w=800&q=80', 4);
